Besides at-rules, you can create an arbitrary CSS rules with className or attribute - they just return selectors of different types:

import { className, attribute } from 'effcss';
// returns string
const cls = className({
padding: '0.5rem',
'&:focus': {
borderBottom: '4px solid grey'
}
});
// returns object
const attr = attribute({
margin: 'auto',
'&:hover': {
outline: '2px solid black',
'.child': {
background: 'grey'
}
}
});
export const Component = () => {
return <div {...attr} className={cls}>
...
</div>
};

